// Parse RSS/Atom XML into structured items, carrying source metadata from Feed List.
const items = $input.all();
const results = [];
const feedErrors = [];
const feedListItems = $('Feed List').all();

for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  const feedMeta = feedListItems[idx]?.json || {};
  const xml = item.json?.data || item.json?.body || '';
  const sourceName = item.json?.sourceName || feedMeta.sourceName || 'Unknown';
  const category = item.json?.category || feedMeta.category || 'tech-news';
  const trust = item.json?.trust || feedMeta.trust || 1;

  if (item.json?.error || item.json?.statusCode >= 400) {
    feedErrors.push({ source: sourceName, error: String(item.json?.error || `HTTP ${item.json?.statusCode || 'error'}`).substring(0, 200) });
    continue;
  }

  if (!xml || xml.length < 100 || xml.includes('<!DOCTYPE html')) {
    feedErrors.push({ source: sourceName, error: 'Empty, too short, or HTML response' });
    continue;
  }

  try {
    const rssItemRegex = /<item[\s>][\s\S]*?<\/item>/gi;
    const rssMatches = xml.match(rssItemRegex) || [];
    const atomEntryRegex = /<entry[\s>][\s\S]*?<\/entry>/gi;
    const atomMatches = xml.match(atomEntryRegex) || [];
    const entries = rssMatches.length > 0 ? rssMatches : atomMatches;
    const isAtom = rssMatches.length === 0 && atomMatches.length > 0;

    if (entries.length === 0) {
      feedErrors.push({ source: sourceName, error: 'No <item> or <entry> tags found' });
      continue;
    }

    for (const entry of entries) {
      function getTag(tag) {
        const cdataRegex = new RegExp(`<${tag}[^>]*>\s*<!\[CDATA\[([\s\S]*?)\]\]>\s*<\/${tag}>`, 'i');
        const cdataMatch = entry.match(cdataRegex);
        if (cdataMatch) return cdataMatch[1].trim();
        const regex = new RegExp(`<${tag}[^>]*>([\s\S]*?)<\/${tag}>`, 'i');
        const match = entry.match(regex);
        return match ? match[1].trim() : '';
      }

      let title = getTag('title').replace(/<[^>]+>/g, '').trim();
      let link = '';
      if (isAtom) {
        const linkMatch = entry.match(/<link[^>]*rel=["']alternate["'][^>]*href=["']([^"']+)["']/i)
          || entry.match(/<link[^>]*href=["']([^"']+)["']/i);
        link = linkMatch ? linkMatch[1] : '';
      } else {
        link = getTag('link');
      }
      const guid = getTag('guid') || getTag('id');
      const pubDateStr = getTag('pubDate') || getTag('published') || getTag('updated') || getTag('dc:date');
      let snippet = getTag('description') || getTag('summary') || getTag('content:encoded') || getTag('content');
      snippet = snippet.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

      if (!title || (!link && !guid)) continue;

      results.push({
        json: {
          title,
          link: link || guid,
          guid: guid || link,
          pubDate: pubDateStr,
          contentSnippet: snippet.substring(0, 500),
          sourceName,
          category,
          trust
        }
      });
    }
  } catch (parseError) {
    feedErrors.push({ source: sourceName, error: String(parseError).substring(0, 200) });
  }
}

if (feedErrors.length > 0) {
  console.log('Feed errors:', JSON.stringify(feedErrors));
}

if (results.length === 0) {
  return [{ json: { _noData: true, feedErrors, message: 'No items parsed from any feed' } }];
}

return results;

const crypto = require('crypto');
const items = $input.all();
const results = [];

const diag = {
  totalInput: items.length,
  noUrlOrTitle: 0,
  olderThanMax: 0,
  passedTimeFilter: 0,
  afterDedup: 0,
  finalOutput: 0,
  sourceBreakdown: {},
  categoryBreakdown: {}
};

if (items.length === 1 && items[0].json._noData) {
  return [{ json: { _skip: true, message: 'No feed data available' } }];
}

function normalizeUrl(urlStr) {
  try {
    const parsed = new URL(urlStr);
    const params = new URLSearchParams(parsed.search);
    ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'utm_name'].forEach(k => params.delete(k));
    const sorted = [...params.entries()].sort((a, b) => a[0].localeCompare(b[0]));
    const q = sorted.length ? '?' + sorted.map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`).join('&') : '';
    const hasCustomPort = parsed.port && !((parsed.protocol === 'http:' && parsed.port === '80') || (parsed.protocol === 'https:' && parsed.port === '443'));
    const port = hasCustomPort ? `:${parsed.port}` : '';
    const path = (parsed.pathname || '/').replace(/\/+$/, '') || '/';
    return `${parsed.protocol}//${parsed.hostname.toLowerCase()}${port}${path}${q}`;
  } catch (error) {
    return (urlStr || '').trim();
  }
}

// ============================================================
// CONFIG
// ============================================================
const MAX_AGE_HOURS = 168;       // 7 days for weekly publishers
const MAX_RESULTS = 40;          // Increased for 3-lane coverage
const SIMILARITY_THRESHOLD = 0.45;
// ============================================================

// === CATEGORY-SPECIFIC SCORING ===
const CYBER_KEYWORDS = [
  { pattern: /cve-\d{4}-\d+/, score: 3 },
  { pattern: /zero-day|0-day|rce|remote code execution/, score: 3 },
  { pattern: /exploit|poc|proof of concept/, score: 2 },
  { pattern: /ransomware|breach|data leak|data exposure/, score: 2 },
  { pattern: /critical|urgent|actively exploited|in the wild/, score: 3 },
  { pattern: /apt|nation.state|state.sponsored/, score: 2 },
  { pattern: /supply.chain|backdoor|trojan/, score: 2 },
  { pattern: /patch tuesday|security update|advisory/, score: 1 },
  { pattern: /cisa|nsa|fbi.*(warn|advisory|alert)/, score: 2 },
  { pattern: /vulnerability disclosure|bug bounty/, score: 1 }
];

const AI_KEYWORDS = [
  { pattern: /\bai\b|\bml\b|machine learning|deep learning/, score: 1 },
  { pattern: /llm|large language model|foundation model/, score: 2 },
  { pattern: /gpt|gemini|claude|copilot|llama|mistral|deepseek|phi-4/, score: 2 },
  { pattern: /open.?source.*(model|weight)|hugging.?face/, score: 2 },
  { pattern: /ai.*(regulation|policy|executive.order|eu.ai.act|safety)/, score: 3 },
  { pattern: /agi|artificial.general|frontier.model/, score: 2 },
  { pattern: /benchmark|eval|mmlu|humaneval|arena/, score: 1 },
  { pattern: /fine.?tun|rlhf|rl.?from|alignment|red.?team/, score: 2 },
  { pattern: /diffusion|stable.?diffusion|midjourney|dall-?e|sora|video.gen/, score: 1 },
  { pattern: /transformer|attention.mechanism|moe|mixture.of.expert/, score: 1 },
  { pattern: /ai.*(funding|raise|valuation|ipo|acquisition)/, score: 2 },
  { pattern: /enterprise.ai|ai.agent|agentic/, score: 2 }
];

const TECH_KEYWORDS = [
  { pattern: /layoff|restructur|workforce.reduction/, score: 2 },
  { pattern: /acqui|merger|buyout|ipo/, score: 2 },
  { pattern: /apple|google|meta|microsoft|amazon|nvidia/, score: 1 },
  { pattern: /android|ios|iphone|pixel|galaxy/, score: 1 },
  { pattern: /cloud|aws|azure|gcp|kubernetes/, score: 1 },
  { pattern: /developer|api.change|sdk|platform.update/, score: 1 },
  { pattern: /chip|semiconductor|gpu|tpu|processor/, score: 2 },
  { pattern: /open.?source|github|linux|kernel/, score: 1 },
  { pattern: /india.*(tech|startup|digital|policy)/, score: 2 },
  { pattern: /privacy|gdpr|dma|antitrust/, score: 1 }
];

// === SOURCE TRUST + WEIGHT ===
const sourceWeight = {
  'Krebs on Security': 4,
  'Schneier on Security': 4,
  'CISA': 5,
  'BleepingComputer': 3,
  'Dark Reading': 3,
  'SecurityWeek': 3,
  'CyberScoop': 3,
  'The Hacker News': 2,
  'MIT Tech Review': 4,
  'AI Snake Oil': 4,
  'Simon Willison': 4,
  'Google AI Blog': 4,
  'OpenAI Blog': 4,
  'Wired AI': 3,
  'The Verge AI': 2,
  'Ars Technica': 3,
  'TechCrunch': 3,
  'The Verge': 3,
  'The Next Web': 2,
  '9to5Google': 2,
  'Google News': 1
};

for (const item of items) {
  const url = item.json.link || item.json.guid || '';
  const title = item.json.title || '';
  if (!url || !title) { diag.noUrlOrTitle++; continue; }

  const normalizedUrl = normalizeUrl(url);
  const hash = crypto.createHash('sha256').update(normalizedUrl).digest('hex');

  let pubDate;
  const rawDate = item.json.pubDate || item.json.isoDate || '';
  if (rawDate) {
    pubDate = new Date(rawDate);
    if (isNaN(pubDate.getTime())) pubDate = new Date();
  } else {
    pubDate = new Date();
  }

  const hoursSince = (Date.now() - pubDate.getTime()) / (1000 * 60 * 60);
  if (hoursSince > MAX_AGE_HOURS) { diag.olderThanMax++; continue; }
  diag.passedTimeFilter++;

  const text = (title + ' ' + (item.json.contentSnippet || '')).toLowerCase();
  const category = item.json.category || 'tech-news';
  const sourceName = item.json.sourceName || 'Unknown';
  const trust = item.json.trust || 1;

  // Base score from source weight
  let score = sourceWeight[sourceName] || 1;

  // Category-specific keyword scoring
  const keywordSets = {
    'cybersecurity': CYBER_KEYWORDS,
    'ai': AI_KEYWORDS,
    'tech-news': TECH_KEYWORDS
  };
  // Score from own category keywords (full weight)
  const ownKeywords = keywordSets[category] || TECH_KEYWORDS;
  for (const kw of ownKeywords) {
    if (kw.pattern.test(text)) score += kw.score;
  }
  // Bonus: cross-category signals at half weight (e.g. AI + security overlap)
  for (const [cat, keywords] of Object.entries(keywordSets)) {
    if (cat === category) continue;
    for (const kw of keywords) {
      if (kw.pattern.test(text)) score += Math.ceil(kw.score * 0.3);
    }
  }

  // Trust bonus
  if (trust >= 4) score += 2;
  else if (trust >= 3) score += 1;

  // Recency boost
  if (hoursSince < 3) score += 3;
  else if (hoursSince < 6) score += 2;
  else if (hoursSince < 12) score += 1;

  // Recency decay for non-breaking after 24h
  if (hoursSince > 24) score -= 1;
  if (hoursSince > 48) score -= 1;

  // Track
  diag.sourceBreakdown[sourceName] = (diag.sourceBreakdown[sourceName] || 0) + 1;
  diag.categoryBreakdown[category] = (diag.categoryBreakdown[category] || 0) + 1;

  results.push({
    json: {
      hash,
      title: title.trim(),
      url,
      normalizedUrl,
      source: sourceName,
      category,
      trust,
      excerpt: (item.json.contentSnippet || '').substring(0, 500),
      publishedAt: pubDate.toISOString(),
      hoursSince: Math.round(hoursSince),
      score,
      isHighPriority: false // set downstream per category
    }
  });
}

if (results.length === 0) {
  return [{ json: { _skip: true, message: 'No articles after scoring', diagnostics: diag } }];
}

results.sort((a, b) => b.json.score - a.json.score);

// === Dedup via trigram clustering ===
function trigrams(str) {
  const s = str.toLowerCase().replace(/[^a-z0-9 ]/g, '').trim();
  const set = new Set();
  for (let i = 0; i <= s.length - 3; i++) set.add(s.substring(i, i + 3));
  return set;
}
function similarity(a, b) {
  const tA = trigrams(a);
  const tB = trigrams(b);
  let overlap = 0;
  for (const t of tA) if (tB.has(t)) overlap++;
  return overlap / Math.max(tA.size, tB.size, 1);
}

const clusters = [];
for (const item of results) {
  let merged = false;
  for (const cluster of clusters) {
    if (similarity(item.json.title, cluster[0].json.title) > SIMILARITY_THRESHOLD) {
      cluster.push(item);
      merged = true;
      break;
    }
  }
  if (!merged) clusters.push([item]);
}

const deduped = clusters.map(cluster => {
  cluster.sort((a, b) => b.json.score - a.json.score);
  const best = { ...cluster[0] };
  best.json = { ...best.json };
  best.json.sourceCount = cluster.length;
  best.json.allSources = [...new Set(cluster.map(c => c.json.source))].join(', ');
  if (cluster.length >= 3) {
    best.json.score += 3;
    best.json.isBreaking = true;
  } else if (cluster.length >= 2) {
    best.json.score += 1;
    best.json.isBreaking = false;
  } else {
    best.json.isBreaking = false;
  }
  return best;
});

deduped.sort((a, b) => b.json.score - a.json.score);
diag.afterDedup = deduped.length;
diag.finalOutput = deduped.length;

if (deduped.length > 0) {
  deduped[0].json._diagnostics = diag;
}

return deduped;

// ============================================================
// CATEGORY BALANCING GATE
// Enforces per-category quotas so one niche doesn't dominate.
// Runs AFTER dedup, BEFORE Notion hash check.
// ============================================================

const items = $input.all();

if (items.length === 1 && (items[0].json._skip || items[0].json._noData)) {
  return items;
}

// === QUOTAS (per cycle) ===
const QUOTAS = {
  'cybersecurity': { target: 10, max: 14, highThreshold: 6 },
  'ai':            { target: 8,  max: 12, highThreshold: 5 },
  'tech-news':     { target: 8,  max: 12, highThreshold: 4 }
};
const TOTAL_CAP = 30;

// Group by category
const buckets = {};
for (const item of items) {
  const cat = item.json.category || 'tech-news';
  if (!buckets[cat]) buckets[cat] = [];
  buckets[cat].push(item);
}

// Sort each bucket by score desc
for (const cat of Object.keys(buckets)) {
  buckets[cat].sort((a, b) => b.json.score - a.json.score);
}

// Pass 1: Fill up to target per category
const selected = [];
const selectedByCategory = {};

for (const [cat, config] of Object.entries(QUOTAS)) {
  const available = buckets[cat] || [];
  const take = Math.min(available.length, config.target);
  for (let i = 0; i < take; i++) {
    // Apply category-specific high-priority threshold
    available[i].json.isHighPriority = available[i].json.score >= config.highThreshold;
    selected.push(available[i]);
  }
  selectedByCategory[cat] = take;
}

// Pass 2: If under TOTAL_CAP, fill remaining slots from any category up to max
if (selected.length < TOTAL_CAP) {
  const remaining = TOTAL_CAP - selected.length;
  const selectedHashes = new Set(selected.map(s => s.json.hash));
  const extras = [];

  for (const [cat, config] of Object.entries(QUOTAS)) {
    const available = buckets[cat] || [];
    const alreadyTaken = selectedByCategory[cat] || 0;
    const canTakeMore = config.max - alreadyTaken;
    for (let i = alreadyTaken; i < alreadyTaken + canTakeMore && i < available.length; i++) {
      if (!selectedHashes.has(available[i].json.hash)) {
        available[i].json.isHighPriority = available[i].json.score >= config.highThreshold;
        extras.push(available[i]);
      }
    }
  }

  // Sort extras by score and take what fits
  extras.sort((a, b) => b.json.score - a.json.score);
  for (let i = 0; i < Math.min(extras.length, remaining); i++) {
    selected.push(extras[i]);
  }
}

// Final sort by score
selected.sort((a, b) => b.json.score - a.json.score);

// Log balance diagnostics
const balanceLog = {};
for (const item of selected) {
  const cat = item.json.category;
  balanceLog[cat] = (balanceLog[cat] || 0) + 1;
}
console.log('=== CATEGORY BALANCE ===', JSON.stringify(balanceLog));

if (selected.length > 0) {
  selected[0].json._balanceDiag = balanceLog;
}

return selected.length > 0 ? selected : [{ json: { _skip: true, message: 'No articles after category balancing' } }];

