const page1 = $('Fetch Existing Hashes').first().json?.results || [];
const page2 = $('Fetch Existing Hashes Page 2').first().json?.results || [];
const existingHashes = new Set();

for (const page of [...page1, ...page2]) {
  const h = page.properties?.Hash?.rich_text?.[0]?.plain_text;
  if (h) existingHashes.add(h);
}

const scored = $('Category Balance Gate').all();
const newItems = scored.filter(item => !item.json._skip && !existingHashes.has(item.json.hash));

if (newItems.length === 0) {
  return [{ json: { _skip: true, message: 'No new articles' } }];
}

return newItems;

const allInputs = $input.all();
const upstream = $('Build Category Prompt').all();
const outputs = [];

const LABEL_REGEX = /^(\*\*)?\s*(headline|lead|body|intro|expert\s*take|what\s*to\s*do|what\s*to\s*watch|key\s*takeaways|why\s*it\s*matters|the\s*bigger\s*picture|meta|tags|slug|category)\s*(\*\*)?\s*[:()]?\s*(\*\*)?$/i;
const CHAR_COUNT_REGEX = /^.*\(\d+\s*chars?\).*$/i;

function extractTitle(text) {
  const lines = text.split('\n').filter(l => l.trim());
  for (const line of lines) {
    const cleaned = line.replace(/\*\*/g, '').replace(/^#+\s*/, '').trim();
    if (LABEL_REGEX.test(cleaned)) continue;
    if (CHAR_COUNT_REGEX.test(cleaned)) continue;
    if (cleaned.length < 15) continue;
    if (/^(meta|tags|slug|category):/i.test(cleaned)) continue;
    return cleaned.substring(0, 200);
  }
  return null;
}

function stripTitleFromBody(bodyText, title) {
  if (!title) return bodyText;
  const lines = bodyText.split('\n');
  return lines.filter(l => {
    const cleaned = l.replace(/\*\*/g, '').replace(/^#+\s*/, '').trim();
    return cleaned !== title;
  }).join('\n').trim();
}

for (let idx = 0; idx < allInputs.length; idx++) {
  const groqResponse = allInputs[idx].json || {};
  const raw = groqResponse?.choices?.[0]?.message?.content || '';

  const body = raw
    .replace(/^META:.+$/gim, '')
    .replace(/^TAGS:.+$/gim, '')
    .replace(/^SLUG:.+$/gim, '')
    .replace(/^CATEGORY:.+$/gim, '')
    .trim();

  const tagsMatch = raw.match(/TAGS:\s*(.+)/i);
  const tags = tagsMatch ? tagsMatch[1].trim() : '';
  const slugMatch = raw.match(/SLUG:\s*(.+)/i);
  const slug = slugMatch ? slugMatch[1].trim() : '';
  const catMatch = raw.match(/CATEGORY:\s*(.+)/i);
  const aiCategory = catMatch ? catMatch[1].trim() : '';

  const prev = upstream[idx]?.json || upstream[0]?.json || {};
  const aiTitle = extractTitle(raw);
  const hasUsableAiBody = body.length >= 180;
  const cleanBody = aiTitle ? stripTitleFromBody(body, aiTitle) : body;

  // === ANTI-HALLUCINATION CHECK ===
  const hasConcreteData = /\d{4}|CVE-|\d+\.\d+|\$\d|%|v\d/.test(cleanBody);
  const hasSourceUrl = prev.url && prev.url.startsWith('http');
  const passesFactCheck = hasConcreteData && hasSourceUrl;

  const fallbackBody = [
    `Lead: ${prev.title || 'Update'}`,
    '',
    (prev.excerpt || 'Fallback draft. AI returned empty or low-quality response.').trim(),
    '',
    `Source: ${prev.source || 'Unknown'}`,
    `URL: ${prev.url || 'N/A'}`,
    `Signals: score=${prev.score || 0}, breaking=${Boolean(prev.isBreaking)}`
  ].join('\n');

  outputs.push({
    json: {
      title: aiTitle || prev.title || 'Untitled',
      bodySafe: (hasUsableAiBody && passesFactCheck) ? cleanBody : fallbackBody,
      tags: tags || prev.category || '',
      slug: slug || '',
      category: aiCategory || prev.category || 'tech-news',
      sourceUrl: prev.url || '',
      hash: prev.hash || '',
      source: prev.source || '',
      score: prev.score || 0,
      isBreaking: prev.isBreaking || false,
      allSources: prev.allSources || prev.source || '',
      aiFallbackUsed: !(hasUsableAiBody && passesFactCheck)
    }
  });
}

return outputs;

function parseRichText(text) {
  const parts = [];
  const regex = /\*\*(.+?)\*\*/g;
  let lastIndex = 0;
  let match;
  while ((match = regex.exec(text)) !== null) {
    if (match.index > lastIndex) {
      parts.push({ type: 'text', text: { content: text.slice(lastIndex, match.index).substring(0, 2000) } });
    }
    parts.push({ type: 'text', text: { content: match[1].substring(0, 2000) }, annotations: { bold: true } });
    lastIndex = regex.lastIndex;
  }
  if (lastIndex < text.length) {
    parts.push({ type: 'text', text: { content: text.slice(lastIndex).substring(0, 2000) } });
  }
  return parts.length ? parts : [{ type: 'text', text: { content: text.substring(0, 2000) } }];
}

function buildBlocks(bodyText) {
  const lines = bodyText.split('\n');
  const blocks = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    if (trimmed.startsWith('## ')) {
      blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: parseRichText(trimmed.slice(3).trim()) } });
    } else if (trimmed.startsWith('### ')) {
      blocks.push({ object: 'block', type: 'heading_3', heading_3: { rich_text: parseRichText(trimmed.slice(4).trim()) } });
    } else if (/^[-*]\s+/.test(trimmed)) {
      blocks.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: parseRichText(trimmed.replace(/^[-*]\s+/, '')) } });
    } else if (/^\d+\.\s+/.test(trimmed)) {
      blocks.push({ object: 'block', type: 'numbered_list_item', numbered_list_item: { rich_text: parseRichText(trimmed.replace(/^\d+\.\s+/, '')) } });
    } else {
      const chunks = trimmed.match(/.{1,2000}/gs) || [trimmed];
      for (const chunk of chunks) {
        blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: parseRichText(chunk) } });
      }
    }
  }
  return blocks.length ? blocks : [{ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: 'Draft body unavailable. Please regenerate.' } }] } }];
}

const title = ($json.title || 'Untitled').substring(0, 2000);
const children = buildBlocks($json.bodySafe || '');

const statusName = $json.aiFallbackUsed ? 'Failed'
  : $json.isBreaking ? 'Ready'
  : 'Draft';

return [{
  json: {
    notionPayload: {
      parent: { database_id: '33a498f5eea880ea91ade7c84a685e6f' },
      properties: {
        'Sr.No': { title: [{ text: { content: title } }] },
        Title: { rich_text: [{ text: { content: title } }] },
        Status: { select: { name: statusName } },
        Type: { select: { name: 'rapid-news' } },
        Category: { select: { name: $json.category } },
        Source: { url: $json.sourceUrl },
        Tags: { rich_text: [{ text: { content: $json.tags || '' } }] },
        Hash: { rich_text: [{ text: { content: $json.hash || '' } }] }
      },
      children
    }
  }
}];

if ($json._skip) {
  return [{ json: { _skipped: true, message: 'Nothing to save' } }];
}
return [{ json: $json }];

const data = $input.first().json;
const vulns = data.vulnerabilities || [];

if (vulns.length === 0) {
  return [{ json: { _skip: true, error: 'No CVEs found', totalResults: data.totalResults || 0 } }];
}

const parsed = vulns.map(v => {
  const cve = v.cve || {};
  const metrics = cve.metrics || {};
  const cvss = metrics.cvssMetricV31?.[0]?.cvssData || metrics.cvssMetricV30?.[0]?.cvssData || null;
  const desc = (cve.descriptions || []).find(d => d.lang === 'en');
  return {
    id: cve.id || 'UNKNOWN',
    description: desc ? desc.value.substring(0, 600) : 'No description',
    cvssScore: cvss ? cvss.baseScore : 0,
    severity: cvss && cvss.baseScore >= 9 ? 'CRITICAL' : 'HIGH',
    attackVector: cvss ? cvss.attackVector : 'UNKNOWN',
    published: cve.published || ''
  };
}).filter(c => c.cvssScore >= 7);

if (parsed.length === 0) {
  return [{ json: { _skip: true, error: 'No high-severity CVEs' } }];
}

parsed.sort((a, b) => b.cvssScore - a.cvssScore);
// Return top 3 instead of just 1
return parsed.slice(0, 3).map(c => ({ json: { ...c, _skip: false } }));

const epssResponse = $input.first().json;
const epssData = epssResponse?.data?.[0] || {};
const epssScore = parseFloat(epssData.epss || '0');
const epssPercentile = parseFloat(epssData.percentile || '0');

const idx = $itemIndex || 0;
const cveItems = $('Has CVEs?').all();
const cve = cveItems[idx]?.json || cveItems[0]?.json || {};

const cvssScore = Number(cve.cvssScore || 0);
const keep = cvssScore >= 9 || epssScore >= 0.05;

return [{
  json: {
    ...cve,
    epssScore,
    epssPercentile,
    epssLabel: epssScore >= 0.5 ? 'ACTIVELY_TARGETED'
      : epssScore >= 0.1 ? 'HIGH_RISK'
      : epssScore >= 0.05 ? 'MODERATE'
      : 'LOW_EXPLOIT_PROB',
    _skip: !keep
  }
}];

return [{
  json: {
    skipped: true,
