const crypto = require('crypto');
const raw = $input.first().json?.choices?.[0]?.message?.content || '';

const body = raw
  .replace(/^META:.+$/gim, '')
  .replace(/^TAGS:.+$/gim, '')
  .replace(/^SLUG:.+$/gim, '')
  .replace(/^CATEGORY:.+$/gim, '')
  .trim();

const tagsMatch = raw.match(/TAGS:\s*(.+)/i);
const tags = tagsMatch ? tagsMatch[1].trim() : 'cve,security,vulnerability';

const LABEL_REGEX = /^(\*\*)?\s*(headline|lead|body|intro|expert\s*take|what\s*to\s*do|meta|tags|slug|category)\s*(\*\*)?\s*[:()]?\s*(\*\*)?$/i;
const CHAR_COUNT_REGEX = /^.*\(\d+\s*chars?\).*$/i;

function extractTitle(text) {
  const lines = text.split('\n').filter(l => l.trim());
  for (const line of lines) {
    const cleaned = line.replace(/\*\*/g, '').replace(/^#+\s*/, '').trim();
    if (LABEL_REGEX.test(cleaned)) continue;
    if (CHAR_COUNT_REGEX.test(cleaned)) continue;
    if (cleaned.length < 15) continue;
    if (/^(meta|tags|slug|category):/i.test(cleaned)) continue;
    return cleaned.substring(0, 200);
  }
  return null;
}

const idx = $itemIndex || 0;
const epssItems = $('Merge EPSS + Filter').all();
const epss = epssItems[idx]?.json || epssItems[0]?.json || {};

const aiTitle = extractTitle(raw);
const cveId = epss.id || '';

const hash = cveId
  ? crypto.createHash('sha256').update(cveId).digest('hex')
  : crypto.createHash('sha256').update(aiTitle || Date.now().toString()).digest('hex');

const fallbackTitle = cveId
  ? `${cveId}: ${(epss.description || 'Security Vulnerability').substring(0, 150)}`
  : 'Untitled CVE Article';

return [{
  json: {
    title: aiTitle || fallbackTitle,
    bodySafe: body.length >= 100 ? body : `${cveId} — CVSS ${epss.cvssScore || 'N/A'}\n\n${epss.description || 'No AI body generated. Review manually.'}`,
    category: 'cybersecurity',
    sourceUrl: `https://nvd.nist.gov/vuln/detail/${cveId}`,
    tags,
    cveId,
    hash,
    epssScore: epss.epssScore || 0,
    epssLabel: epss.epssLabel || '',
    aiFallbackUsed: body.length < 100
  }
}];

function parseRichText(text) {
  const parts = [];
  const regex = /\*\*(.+?)\*\*/g;
  let lastIndex = 0;
  let match;
  while ((match = regex.exec(text)) !== null) {
    if (match.index > lastIndex) {
      parts.push({ type: 'text', text: { content: text.slice(lastIndex, match.index).substring(0, 2000) } });
    }
    parts.push({ type: 'text', text: { content: match[1].substring(0, 2000) }, annotations: { bold: true } });
    lastIndex = regex.lastIndex;
  }
  if (lastIndex < text.length) {
    parts.push({ type: 'text', text: { content: text.slice(lastIndex).substring(0, 2000) } });
  }
  return parts.length ? parts : [{ type: 'text', text: { content: text.substring(0, 2000) } }];
}

function buildBlocks(bodyText) {
  const lines = bodyText.split('\n');
  const blocks = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    if (trimmed.startsWith('## ')) {
      blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: parseRichText(trimmed.slice(3).trim()) } });
    } else if (trimmed.startsWith('### ')) {
      blocks.push({ object: 'block', type: 'heading_3', heading_3: { rich_text: parseRichText(trimmed.slice(4).trim()) } });
    } else if (/^[-*]\s+/.test(trimmed)) {
      blocks.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: parseRichText(trimmed.replace(/^[-*]\s+/, '')) } });
    } else if (/^\d+\.\s+/.test(trimmed)) {
      blocks.push({ object: 'block', type: 'numbered_list_item', numbered_list_item: { rich_text: parseRichText(trimmed.replace(/^\d+\.\s+/, '')) } });
    } else {
      const chunks = trimmed.match(/.{1,2000}/gs) || [trimmed];
      for (const chunk of chunks) {
        blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: parseRichText(chunk) } });
      }
    }
  }
  return blocks.length ? blocks : [{ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: 'No content available' } }] } }];
}

const title = ($json.title || 'Untitled Article').substring(0, 2000);
const children = buildBlocks($json.bodySafe || '');
const statusName = $json.aiFallbackUsed ? 'Failed' : 'Draft';

return [{
  json: {
    notionPayload: {
      parent: { database_id: '33a498f5eea880ea91ade7c84a685e6f' },
      properties: {
        'Sr.No': { title: [{ text: { content: title } }] },
        Title: { rich_text: [{ text: { content: title } }] },
        Status: { select: { name: statusName } },
        Type: { select: { name: 'rapid-news' } },
        Category: { select: { name: $json.category || 'cybersecurity' } },
        Source: { url: $json.sourceUrl || 'https://nvd.nist.gov' },
        Tags: { rich_text: [{ text: { content: $json.tags || '' } }] },
        Hash: { rich_text: [{ text: { content: $json.hash || '' } }] }
      },
      children
    }
  }
}];

const pages = $input.first().json?.results || [];

// Group by category for the newsletter
const byCategory = { ai: [], cybersecurity: [], 'tech-news': [] };

for (const p of pages) {
  const title = p.properties?.Title?.rich_text?.[0]?.plain_text || p.properties?.Name?.title?.[0]?.plain_text || 'Untitled';
  const url = p.properties?.Source?.url || '';
  const category = p.properties?.Category?.select?.name || 'tech-news';
  const tags = p.properties?.Tags?.rich_text?.[0]?.plain_text || '';
  const item = { title, url, category, tags };

  if (byCategory[category]) {
    byCategory[category].push(item);
  } else {
    byCategory['tech-news'].push(item);
  }
}

// Build structured article list with category sections
let articleList = '';
for (const [cat, articles] of Object.entries(byCategory)) {
  if (articles.length === 0) continue;
  articleList += `\n=== ${cat.toUpperCase()} (${articles.length} articles) ===\n`;
  for (const a of articles) {
    articleList += `• ${a.title}\n  ${a.url}\n`;
  }
}

return [{ json: {
  articleList,
  articleCount: pages.length,
  aiCount: byCategory.ai.length,
  cyberCount: byCategory.cybersecurity.length,
  techCount: byCategory['tech-news'].length
} }];

const raw = $input.first().json?.choices?.[0]?.message?.content || '';
const subject = 'The TechRupt Brief - Week of ' + new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

function parseRichText(text) {
