        Category: { select: { name: 'tech-news' } },
        Tags: { rich_text: [{ text: { content: 'newsletter,weekly,digest' } }] }
      },
      children: blocks.length ? blocks.slice(0, 100) : [
        { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: 'No content generated' } }] } }
      ]
    }
  }
}];

const errorData = $input.first().json;
const timestamp = new Date().toISOString();
const nodeName = errorData?.execution?.lastNodeExecuted || 'Unknown';
const rawError = errorData?.execution?.error ?? errorData?.error ?? errorData;
let errorMsg;
if (typeof rawError === 'string') { errorMsg = rawError; }
else if (rawError && typeof rawError === 'object') { errorMsg = JSON.stringify(rawError); }
else { errorMsg = String(rawError || 'Unknown error'); }
errorMsg = errorMsg.substring(0, 1000);
return [{ json: { alertText: `⚠️ TechRupt Workflow Error\n\nNode: ${nodeName}\nTime: ${timestamp}\nError: ${errorMsg}`, timestamp, nodeName, errorMsg } }];

const pages = $input.first().json?.results || [];
const categoryCount = {};
